class Solution {
    public int countWinningSequences(String s) {
        int n = s.length();
        int result = 0;
        for (int i = 0; i < n; i++) {
            if (s.charAt(i) == 'F' && s.charAt(i + 1) != 'F') {
                result += 2;
            } else if (s.charAt(i) == 'W' && s.charAt(i + 1) != 'W') {
                result += 2;
            } else if (s.charAt(i) == 'E' && s.charAt(i + 1) != 'E') {
                result += 2;
            }
        }
        return result % 1000000007;
    }
}
```

